ruleContent.content:
@js:
const doc = org.jsoup.Jsoup.parse(result);
const servers = [];
doc.select('[data-server]').forEach(e => servers.push(e.attr('data-server')));
const server = servers[source.getVariable()] || servers[0];

let html = '';
doc.select('.chapter-imgs img').forEach(e => html += `<img src="${server + e.attr('data-url')}">\n`);
html;

jsLib:
function getData() {
var Data = this.source.getVariable();
if (Data == "" || Data == undefined) {
return {};
}
try {
return JSON.parse(String(Data));
} catch (e) {
return {};
}
}
function getPage() {
var data = getData.call(this);
var startPage = (data.page == "" || data.page == undefined) ? '' : parseInt(data.page)-1;
return startPage;
}

loginUrl:
function login() {
var loginInfo = source.getLoginInfoMap() || {};
var pageInput = loginInfo['发现起始页'];
if (!pageInput || pageInput == "" || pageInput == undefined || pageInput == null) {
pageInput = "1";
loginInfo['发现起始页'] = pageInput;       source.putLoginInfo(JSON.stringify(loginInfo));
}
var pageData = {"page": pageInput};
source.setVariable(JSON.stringify(pageData));
}
function web() {
java.startBrowser(`{{getUrl2()}}`, baseUrl);
java.toast('\n🌐 '+getUrl2());
}

ruleExplore.bookList:
@js:
var a=java.getElements('[class="grid gap-3 grid-cols-2 md:grid-cols-3 lg:grid-cols-4"]>div');
var b=parseInt(String(baseUrl).replace(/.*page=(\d+)/,'$1'));
//java.log(b);
var c=parseInt(java.getString('[class="relative z-0 inline-flex flex-wrap shadow-sm rounded-md"]@a.-2@text'));
//java.log(c);
var d=parseInt(java.getString('[class="relative inline-flex items-center px-4 py-2 -ml-px text-sm font-medium text-white bg-gray-500 border cursor-default leading-5"]@text'));
//java.log(d);
if (d<c) {
java.toast('第'+b+'/'+c+'页');
result=a;
} else if (d=b){
java.toast('第'+b+'/'+d+'页');
result=a;
}
result

ruleToc.chapterList:
@js:
book.type=64;
book.setUseReplaceRule(false);
var last = java.getString('[class="relative inline-flex items-center px-4 py-2 -ml-px text-sm font-medium text-gray-700 bg-white border border-gray-300 leading-5 hover:text-gray-500 focus:z-10 focus:outline-none focus:ring ring-gray-300 focus:border-blue-300 active:bg-gray-100 active:text-gray-700 transition ease-in-out duration-150"][-1]@href');
//java.log(last);
if (last && (a = last.match(/(.*page=)(\d+)/))) {
var list = [];
for (var i = 1; i <= a[2]; i++) {
list.push({ text: "第" + i + "页", href: a[1] + i });
}
list;
} else {
[{ text: "正文", href:""}];
}

