        java.ajax(url);
        var time = new Date().getTime() - start;
        var sec = (time / 1000).toFixed(2);
        var text, icon;
        if (time < 300) {
            text = "极快";
            icon = "🚀";
        } else if (time < 600) {
            text = "快速";
            icon = "👍";
        } else if (time < 1000) {
            text = "良好";
            icon = "👌";
        } else if (time < 2000) {
            text = "稍慢";
            icon = "💡";
        } else if (time < 5000) {
            text = "较慢";
            icon = "🐢";
        } else {
            text = "很慢";
            icon = "⏳";
