function Login() {
let rkey = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
let cv='';
for (let i = 0; i < 128; i++) {
	let ra = Math.floor(Math.random()*rkey.length);
	cv+=rkey.charAt(ra);}

let aly = new JavaImporter(
Packages.cn.hutool.crypto.digest.Digester,
Packages.cn.hutool.core.codec.Base64,
Packages.cn.hutool.crypto.digest.DigestAlgorithm);
with (aly) {
	//转ASCII数组
	let asBs =  Packages.java.lang.String(cv).getBytes("US-ASCII");
	//创建SHA256并计算
	let digester = new Digester(DigestAlgorithm.SHA256);
	let hashBs = digester.digest(asBs);
	//Base64URL编码并移除填充
	var codeChallenge  = Base64.encodeUrlSafe(hashBs);
}

let urllg =`https://app-api.pixiv.net/web/v1/login?code_challenge=${codeChallenge}&code_challenge_method=S256&client=pixiv-android`;
reck();
//防止重定向错误，清书源cookie。也需要手动清内置浏览器cookie

let wbua=java.getWebViewUA().replaceAll("; wv| Version\/4.0",'')+'';
if (/HUA\s*WEI/i.test(wbua))
wbua="Mozilla/5.0 (Linux; Android 14; RMX3366 Build/UKQ1.230924.001) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/135.0.7049.100 Mobile Safari/537.36";

let bb=java.startBrowserAwait(urllg+`,{
"headers":{
	"User-Agent": "${wbua}"
	}}`,'登录',false).body();
let code;
if (bb.includes('<title>Online com')) {
sleep(600);
java.toast('稍等');
let over = java.webViewGetOverrideUrl(bb,'https://app-api.pixiv.net/','','pixiv:.*');
code = over.match(/code=([^&]+)/);
}
reck();

let token;
if (code) {
let tkurl = 'https://oauth.secure.pixiv.net/auth/token';
let headers = gethd();
let body = `code_verifier=${cv}&code=${code[1]}&grant_type=authorization_code&redirect_uri=https://app-api.pixiv.net/web/v1/users/auth/pixiv/callback&client_id=MOBrBDS8blbauoSck0ZfDbtuzpyT&client_secret=lsACyCD94FhDUtGTXi3QzcFE2uU1hqtDaKeqrdwj&include_policy=true`;
let tkr = java.post(tkurl,body,headers);
//java.log(tkr.body());
token = tkr.body().match(/refresh_token":"([^"]+)/);
}

