eval(String(source.loginUrl));

var URL =  $$$.url;
var lineType = $$$.lineType || '主线路'; 
var shunt = $$$.shunt || 1;
var weekIndex = $$$.weekIndex || 0; 
var list = [];

function push(title, url, size) { 
    list.push({
        "title": title,
        "url": url,
        "style": {
            "layout_flexGrow": 1,
            "layout_flexBasisPercent": size
        }
    });
}

var urlHint = (lineType === '备用线路') ? ' (备用线路)' : (lineType === '国际通用' ? ' (国际通用)' : (lineType === '东南亚' ? ' (东南亚)' : ' (主线路)'));

push('❗❗为空请获取/更换链接，然后刷新❗❗','', 1);
push('[▶ '+$$$.name+' ◀]', '', 1);
push('[ '+$$$.url + urlHint + ' 分流' + $$$.shunt + ' ]', '', 1);

var sortConfigs = [
  { key: 'mr', title: '按时间' },
  { key: 'mv', title: '按阅读' },
  { key: 'tf', title: '按最爱' },
  { key: 'mo', title: '按收藏' },
  { key: 'tr', title: '按评分' },
  { key: 'md', title: '按评论' },
  { key: 'mp', title: '按图片' }
];

var categories = [
["全部", "albums?o={key}&page="],
  ["COS", "albums/another/sub/cosplay?o={key}&page="],
  ["3D", "search/photos?search_query=3D&o={key}&page="],
  ["韩漫", "albums/hanman?o={key}&page="],
  ["热门", "albums?o={key}&page="],
  ["单本", "albums/single?o={key}&page=<,{{page}}>"],
  ["CG", "albums/doujin/sub/CG?o={key}&page=<,{{page}}>"],
  ["青年漫", "albums/single/sub/youth?o={key}&page=<,{{page}}>"],
  ["短篇", "albums/short?o={key}&page=<,{{page}}>"],
  ["同人", "albums/doujin?o={key}&page=<,{{page}}>"],
  ["其他", "albums/another?o={key}&page=<,{{page}}>"],
  ["小说", "novels?o=mv?o={key}&page=<,{{page}}>"],
  ["美漫", "albums/meiman?o={key}&page=<,{{page}}>"],
  ["C106&推荐本本", "promotes/29?o={key}&page=<,{{page}}>"],
  ["禁漫去码&全彩化", "promotes/30?o={key}&page=<,{{page}}>"],
  ["禁漫汉化组", "search/photos?main_tag=0&search_query=%E7%A6%81%E6%BC%AB%E6%B1%89%E5%C%96%E7%BB%84?o={key}&page=<,{{page}}>"]
];

var currentTagIndex = Math.min(Math.max($$$.tag || 0, 0), sortConfigs.length - 1);
var currentKey = sortConfigs[currentTagIndex].key;
var currentTitle = sortConfigs[currentTagIndex].title;


push('🏷️分类标签---' + currentTitle + '🏷️', '', 1);



for (var j = 0; j < categories.length; j++) {
  var arr = categories[j];
  var t = arr[0];
  var u = arr[1];
  var url = URL + '/' + u.replace('{key}', currentKey);
  if (u.indexOf('<,{{page}}>') === -1) {
    url += '{{page}}';
  }
  push(t, url, 0.25);
}
push('🏷️每周必看 (当前: ' + weekIndex + ', 范围 0-210,0为最新)🏷️','',1); 

try {
    var pageHtml = java.ajax(URL + '/albums'); 
    var albumRegex = /href="\/album\/(\d+)"/g;
    var matches = [];
    var match;
    while ((match = albumRegex.exec(pageHtml)) !== null) {
        matches.push(match[1]);
    }
    if (matches.length > 0) {
        var randomId = matches[Math.floor(Math.random() * matches.length)];
        var randomUrl = URL + '/album/' + randomId;
        push('🎲 随机看一本(仅测试版可用) 🎲', randomUrl, 1);
    }
} catch (e) {
    java.log('Failed to fetch random album: ' + e);
}

var weeklyTypes = [['日漫','manga'],['韩漫','hanman'],['其他','another']];
for (var i = 0; i < weeklyTypes.length; i++) {
    var arr = weeklyTypes[i];
    var t = arr[0];
    var p = arr[1];
    push(t, URL + '/week/' + weekIndex + '?skdad=1&type=' + p + '&page={{page}}', 0.25);
}



push('🏷️每周连载🏷️', '', 1);
let _list = [["周一", "serialization/1&page="], ["周二", "serialization/2&page="], ["周三", "serialization/3&page="], ["周四", "serialization/4&page="],["周五", "serialization/5&page="], ["周六", "serialization/6&page="], ["周日", "serialization/7&page="], ["已完结", "serialization/7&page="]];
    _list.map(([t, u]) => {
    	    push(t, `${URL}/${u}` + '{{page}}', 0.25);
    	});
push('👁‍🗨阅读排行榜👁‍🗨', '', 1);
var typeList = [["日榜", "&t=t"], ["周榜", "&t=w"], ["月榜", "&t=m"],["总榜", ""]];
for (var k = 0; k < typeList.length; k++) {
    var arr = typeList[k];
    var t = arr[0];
    var type = arr[1];
    push(t, URL + '/albums?o=mv' + type + '&page=' + '{{page}}' , 0.2);
}

push('♥️收藏排行榜♥️', '', 1);
for (var l = 0; l < typeList.length; l++) {
    var arr = typeList[l];
    var t = arr[0];
    var type = arr[1];
    push(t, URL + '/albums?o=mo' + type + '&page=' + '{{page}}', 0.2);
}

var sorts1 = ["無修正","劇情向","青年漫","校服","純愛","人妻","教師","百合","Yaoi","性轉","女裝","癡女","全彩","女性向","完結","純愛","禁漫漢化組"];
var sorts2 = ["御姐","熟女","未成年","巨乳","貧乳","女性支配","教師","女僕","護士","泳裝","眼鏡","連褲襪","其他制服","兔女郎"];
var sorts3 = ["群交","足交","束縛","肛交","阿黑顏","藥物","扶他","調教","野外露出","催眠","自慰","觸手","獸交","亞人","怪物女孩","皮物","附身","ryona","骑大车"];
var sorts4 = ["CG","重口","獵奇","非H","血腥暴力","站長推薦"];
var sortCriteria = [
  { label: '🏷️标签---按时间🏷️', sort: 'mr' },
  { label: '🏷️标签---按阅读🏷️', sort: 'mv' },
  { label: '🏷️标签---按最爱🏷️', sort: 'tf' },
  { label: '🏷️标签---按收藏🏷️', sort: 'mo' },
  { label: '🏷️标签---按评分🏷️', sort: 'tr' },
  { label: '🏷️标签---按评论🏷️', sort: 'md' },
  { label: '🏷️标签---按图片🏷️', sort: 'mp' }
];

var sort =  sortCriteria[$$$.tag].sort;
var label = sortCriteria[$$$.tag].label;

push(label, '', 1);
push('▶主题A漫◀','', 1);
for (var m = 0; m < sorts1.length; m++) {
    var s = sorts1[m];
    push(s, URL + '/search/photos?search_query=' + s + '&o=' + sort + '&page=' + '{{page}}', 0.25);
}

push('▶角色/扮演◀','', 1);
for (var n = 0; n < sorts2.length; n++) {
    var s = sorts2[n];
    push(s, URL + '/search/photos?search_query=' + s + '&o=' + sort + '&page=' + '{{page}}', 0.25);
}

push('▶特殊PLAY◀','', 1);
for (var p = 0; p < sorts3.length; p++) {
