push('▶其他◀','', 1);
for (var q = 0; q < sorts4.length; q++) {
    var s = sorts4[q];
    push(s, URL + '/search/photos?search_query=' + s + '&o=' + sort + '&page=' + '{{page}}', 0.25);
}

JSON.stringify(list);

