	};
    if (!cachedPageHtml) {
        cachedPageHtml = java.ajax('https://jmcomicqa.cc');
    }
    var randomIndex = getRandomUnusedIndex();
    var currentRegex = regexList[randomIndex];
    var matchResult = cachedPageHtml.match(currentRegex);
    var url = matchResult ? matchResult[1] : $$$.url;

    var lineType = randomIndex === 0 ? '主线路' : '备用线路';
