}

var P = ['时间', '阅读', '最爱', '收藏', '评分', '评论', '图片'];

function typeP(e) {
    if (e == undefined || e < 0 || e >= P.length) {
        e = 0;
    }
    return P[e];
}

function tag(e) {
    if (e == $$$.tag) {
        return log('【标签切换提示】' + n(2) + '已经选择[' + typeP(e) + ']，无需更换');
    }
    log('【标签切换提示】' + n(2) + '已经切换到[' + typeP(e) + ']，请刷新探索页');
    $$$.tag = e;
    return put($$$);
}

function url() {
    if (!cachedPageHtml) {
        cachedPageHtml = java.ajax('https://jmcomicqa.cc');
    }
    var randomIndex = getRandomUnusedIndex();
    var currentRegex = regexList[randomIndex];
    var matchResult = cachedPageHtml.match(currentRegex);
    var url = matchResult ? matchResult[1] : $$$.url;

    var lineType = randomIndex === 0 ? '主线路' : '备用线路';
    var lineHint = randomIndex === 0 ? ' (默认主线路)' : ' (备用线路)';

    if (url == $$$.url) {
        return log('【站点提示】' + n(2) + '站点无需更换，当前为' + lineHint);
    }
    log('站点变更:' + url + lineHint);
    $$$.url = url;
    $$$.lineType = lineType;
    return put($$$);
}

function setIntlUrl() {
    if (typeof $$$.intlLinkIndex === 'undefined') $$$.intlLinkIndex = 0;
    $$$.intlLinkIndex = ($$$.intlLinkIndex + 1) % intlLinks.length;
    var newUrl = intlLinks[$$$.intlLinkIndex];
    $$$.url = newUrl;
    $$$.lineType = '国际通用，需魔法';
    put($$$);
    log('【国际站点】已切换 (' + ($$$.intlLinkIndex + 1) + '/' + intlLinks.length + '): ' + newUrl + n(2) + '请刷新探索页');
}

function setSeaUrl() {
    if (typeof $$$.seaLinkIndex === 'undefined') $$$.seaLinkIndex = 0;
    $$$.seaLinkIndex = ($$$.seaLinkIndex + 1) % seaLinks.length;
    var newUrl = seaLinks[$$$.seaLinkIndex];
    $$$.url = newUrl;
    $$$.lineType = '东南亚，需魔法';
    put($$$);
    log('【东南亚站点】已切换 (' + ($$$.seaLinkIndex + 1) + '/' + seaLinks.length + '): ' + newUrl + n(2) + '请刷新探索页');
}

function toggleShunt() {
    var newShunt = $$$.shunt + 1;
    if (newShunt > 4) {
        newShunt = 1;
    }
    log('【分流切换提示】' + n(2) + '已切换分流: ' + $$$.shunt + ' -> ' + newShunt + '，请刷新探索页');
    $$$.shunt = newShunt;
    return put($$$);
}


function shunt(e) {
    if (e < 1 || e > 4) {
        return log('【分流提示】' + n(2) + '分流值不合法，范围为1-4。');
    }
    if (e == $$$.shunt) {
        return log('【分流切换提示】' + n(2) + '已经选择分流[' + e + ']，无需更换');
    }
    log('【分流切换提示】' + n(2) + '已经切换到分流[' + e + ']，请刷新探索页');
    $$$.shunt = e;
    return put($$$);}

